const states = msg.payload?.states || [];

if (!Array.isArray(states) || states.length === 0) {
    return null;
}

function inPortugal(lat, lon) {
    const mainland = lat >= 36.8 && lat <= 42.2 && lon >= -9.6 && lon <= -6.0;
    const madeira = lat >= 32.5 && lat <= 33.5 && lon >= -17.5 && lon <= -16.0;
    const azores = lat >= 36.5 && lat <= 40.0 && lon >= -31.5 && lon <= -24.5;

    return mainland || madeira || azores;
}

msg.payload = states
  .filter(s => s[5] && s[6])
  .map(s => ({
    id: s[0],
    callsign: s[1]?.trim(),
    country: s[2],
    lon: s[5],
    lat: s[6],
    altitude: s[7],
    velocity: s[9],
    heading: s[10]
  }))
  .filter(f => inPortugal(f.lat, f.lon));

if (msg.payload.length === 0) {
    return null;
}

return msg;

const f = msg.payload;
msg.flight = f;
msg.url = `https://api.open-meteo.com/v1/forecast?latitude=${f.lat}&longitude=${f.lon}&current_weather=true`;
return msg;

const w = msg.payload?.current_weather;
const f = msg.flight;

msg.payload = {
  ...f,
  weather: w ? {
    temperature: w.temperature,
    windspeed: w.windspeed,
    winddirection: w.winddirection,
    weathercode: w.weathercode
  } : null
};

return msg;
